            throw new ScriptExecutionException("Failed to compile Groovy script.", e);
        } catch (Throwable t) {
            // 运行期异常（空指针、算术异常、用户逻辑错误等）
            throw new ScriptExecutionException("Failed to execute Groovy script.", t);
        }
    }

    /**
     * 脚本执行异常，封装编译与运行期的底层异常，方便调用方处理。
     */
    public static class ScriptExecutionException extends RuntimeException {
        public ScriptExecutionException(String message, Throwable cause) {
            super(message, cause);
        }
    }
}

